'use client';

import { useState, useEffect } from 'react';
import '@/presentation/styles/dashboard.css';

export default function ResidenteReservas() {
    const [reservas, setReservas] = useState<any[]>([]);
    const [recursos, setRecursos] = useState<any[]>([]);
    const [isModalOpen, setIsModalOpen] = useState(false);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState('');
    const [idReservaEditando, setIdReservaEditando] = useState<number | null>(null);

    // Form State
    const [idRecurso, setIdRecurso] = useState('');
    const [fechaInicio, setFechaInicio] = useState('');
    const [horaInicio, setHoraInicio] = useState('08:00');
    const [fechaFin, setFechaFin] = useState('');
    const [horaFin, setHoraFin] = useState('10:00');

    const fetchReservasYRecursos = async () => {
        try {
            const [resReservas, resRecursos] = await Promise.all([
                fetch('/api/reservas').then(r => r.json()),
                fetch('/api/recursos').then(r => r.json())
            ]);
            setReservas(resReservas.reservas || []);
            setRecursos(resRecursos.recursos || []);
        } catch (err) {
            console.error(err);
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        fetchReservasYRecursos();
    }, []);

    const resetForm = () => {
        setIdRecurso('');
        setFechaInicio('');
        setHoraInicio('08:00');
        setFechaFin('');
        setHoraFin('10:00');
        setIdReservaEditando(null);
        setError('');
    };

    const handleCreateOrUpdate = async (e: React.FormEvent) => {
        e.preventDefault();
        setError('');

        const start = new Date(`${fechaInicio}T${horaInicio}`);
        const end = new Date(`${fechaFin}T${horaFin}`);

        try {
            const method = idReservaEditando ? 'PUT' : 'POST';
            const url = idReservaEditando ? `/api/reservas/${idReservaEditando}` : '/api/reservas';

            const res = await fetch(url, {
                method,
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    idRecurso: parseInt(idRecurso),
                    fechaInicio: start.toISOString(),
                    fechaFin: end.toISOString()
                })
            });

            const data = await res.json();
            if (!res.ok) {
                setError(data.message);
                return;
            }

            setIsModalOpen(false);
            resetForm();
            fetchReservasYRecursos();
        } catch (err) {
            setError('Error al procesar la solicitud');
        }
    };

    const handleAbrirEdicion = (res: any) => {
        const start = new Date(res.fechaInicio);
        const end = new Date(res.fechaFin);

        setIdReservaEditando(res.idReserva);
        setIdRecurso(res.recurso?.idRecurso.toString() || '');
        setFechaInicio(start.toISOString().split('T')[0]);
        setHoraInicio(start.toTimeString().slice(0, 5));
        setFechaFin(end.toISOString().split('T')[0]);
        setHoraFin(end.toTimeString().slice(0, 5));

        setIsModalOpen(true);
    };

    const handleCancelar = async (id: number) => {
        if (!confirm('¿Seguro de cancelar esta reserva?')) return;
        try {
            await fetch(`/api/reservas/${id}`, { method: 'DELETE' });
            fetchReservasYRecursos();
        } catch (err) {
            console.error(err);
        }
    };

    if (loading) return <div>Cargando...</div>;

    return (
        <div>
            <div className="dashboard-header">
                <h2>Mis Reservas</h2>
                <button className="btn-primary" onClick={() => { resetForm(); setIsModalOpen(true); }}>
                    + Nueva Reserva
                </button>
            </div>

            <div className="card-grid">
                {reservas.length === 0 ? (
                    <p style={{ color: '#94a3b8' }}>Aún no tienes reservas registradas.</p>
                ) : (
                    reservas.map((res: any) => (
                        <div key={res.idReserva} className="glass-card">
                            <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '10px' }}>
                                <h3 style={{ fontSize: '1.2rem', color: '#fff' }}>{res.recurso?.nombre}</h3>
                                <span className={`tag-status tag-${res.estadoReserva.toLowerCase()}`}>
                                    {res.estadoReserva}
                                </span>
                            </div>
                            <p style={{ color: '#94a3b8', fontSize: '0.9rem', marginBottom: '5px' }}>
                                <strong>Desde:</strong> {new Date(res.fechaInicio).toLocaleString()}
                            </p>
                            <p style={{ color: '#94a3b8', fontSize: '0.9rem', marginBottom: '15px' }}>
                                <strong>Hasta:</strong> {new Date(res.fechaFin).toLocaleString()}
                            </p>

                            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                                <div>
                                    <span style={{ color: '#a5b4fc', fontWeight: '600' }}>
                                        ${res.costoTotal}
                                    </span>
                                </div>
                                <div style={{ display: 'flex', gap: '0.5rem' }}>
                                    {res.estadoReserva === 'Confirmada' && (
                                        <>
                                            <button onClick={() => handleAbrirEdicion(res)} className="btn-secondary">
                                                Editar
                                            </button>
                                            <button onClick={() => handleCancelar(res.idReserva)} className="btn-danger">
                                                Cancelar
                                            </button>
                                        </>
                                    )}
                                </div>
                            </div>
                        </div>
                    ))
                )}
            </div>

            {isModalOpen && (
                <div className="modal-overlay">
                    <div className="modal-content">
                        <h3 style={{ marginBottom: '1.5rem', fontSize: '1.5rem' }}>
                            {idReservaEditando ? 'Editar Reserva' : 'Solicitar Reserva'}
                        </h3>
                        <form onSubmit={handleCreateOrUpdate}>
                            <div style={{ marginBottom: '1rem' }}>
                                <label style={{ display: 'block', marginBottom: '0.5rem', color: '#94a3b8' }}>Recurso a Reservar</label>
                                <select
                                    required
                                    value={idRecurso}
                                    onChange={e => setIdRecurso(e.target.value)}
                                    style={{ width: '100%', padding: '0.8rem', background: 'rgba(0,0,0,0.3)', border: '1px solid rgba(255,255,255,0.1)', color: 'white', borderRadius: '8px' }}
                                >
                                    <option value="">Seleccione un recurso...</option>
                                    {recursos.map(r => (
                                        <option key={r.idRecurso} value={r.idRecurso}>{r.nombre} (${r.costoPorReserva})</option>
                                    ))}
                                </select>
                            </div>

                            <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '1rem', marginBottom: '1rem' }}>
                                <div>
                                    <label style={{ display: 'block', marginBottom: '0.5rem', color: '#94a3b8' }}>Fecha Inicio</label>
                                    <input type="date" required value={fechaInicio} onChange={e => setFechaInicio(e.target.value)} style={{ width: '100%', padding: '0.8rem', background: 'rgba(0,0,0,0.3)', border: '1px solid rgba(255,255,255,0.1)', color: 'white', borderRadius: '8px', colorScheme: 'dark' }} />
                                </div>
                                <div>
                                    <label style={{ display: 'block', marginBottom: '0.5rem', color: '#94a3b8' }}>Hora Inicio</label>
                                    <input type="time" required value={horaInicio} onChange={e => setHoraInicio(e.target.value)} style={{ width: '100%', padding: '0.8rem', background: 'rgba(0,0,0,0.3)', border: '1px solid rgba(255,255,255,0.1)', color: 'white', borderRadius: '8px', colorScheme: 'dark' }} />
                                </div>
                            </div>

                            <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '1rem', marginBottom: '1.5rem' }}>
                                <div>
                                    <label style={{ display: 'block', marginBottom: '0.5rem', color: '#94a3b8' }}>Fecha Fin</label>
                                    <input type="date" required value={fechaFin} onChange={e => setFechaFin(e.target.value)} style={{ width: '100%', padding: '0.8rem', background: 'rgba(0,0,0,0.3)', border: '1px solid rgba(255,255,255,0.1)', color: 'white', borderRadius: '8px', colorScheme: 'dark' }} />
                                </div>
                                <div>
                                    <label style={{ display: 'block', marginBottom: '0.5rem', color: '#94a3b8' }}>Hora Fin</label>
                                    <input type="time" required value={horaFin} onChange={e => setHoraFin(e.target.value)} style={{ width: '100%', padding: '0.8rem', background: 'rgba(0,0,0,0.3)', border: '1px solid rgba(255,255,255,0.1)', color: 'white', borderRadius: '8px', colorScheme: 'dark' }} />
                                </div>
                            </div>

                            {error && <div style={{ color: '#ef4444', marginBottom: '1rem', fontSize: '0.9rem' }}>{error}</div>}

                            <div style={{ display: 'flex', gap: '1rem', justifyContent: 'flex-end' }}>
                                <button type="button" onClick={() => { setIsModalOpen(false); resetForm(); }} style={{ background: 'transparent', color: '#94a3b8', border: 'none', cursor: 'pointer', padding: '0.5rem 1rem' }}>Cancelar</button>
                                <button type="submit" className="btn-primary">
                                    {idReservaEditando ? 'Guardar Cambios' : 'Confirmar Reserva'}
                                </button>
                            </div>
                        </form>
                    </div>
                </div>
            )}
        </div>
    );
}
